unset FZF_DEFAULT_OPTS; ls|command fzf --preview "bat {} 2>/dev/null||ls {}" --preview-window hidden --ansi -m --bind 'q:abort,0:change-preview-window(right,50%|bottom,40%|hidden),tab:toggle+down+transform-header:[ "$FZF_SELECT_COUNT" -gt 0 ] && colight=(110 209 143 103 205 77 150 194 77 131 194 110 152 149 188 146 189 146 218 188 78 181); fl=($(cat {+f})); for i in ${!fl[*]}; do printf %b "\e[38;5;${colight[i]}m${fl[i]} "; done|tr -s "\n" " "|fmt -w $((FZF_COLUMNS*2-5))' --info inline
